// ─── QUESTION BANK: 300+ Questions across all 5 domains ─────────────────────
// Derived from: Professor Messer N10-009 Course Notes, Craig Zacker Practice Tests,
// Emmett Dulaney Exam Cram, Todd Lammle Study Guide

const QUESTIONS = [
  // ═══════════════════════════════════════════════════════════════════════════
  // DOMAIN 1.0: NETWORKING CONCEPTS (23% of exam) — ~70 questions
  // ═══════════════════════════════════════════════════════════════════════════

  // --- 1.1 OSI Model ---
  {id:"1-001",domain:"1.0",sub:"1.1",type:"single",q:"Which layer of the OSI model is responsible for logical addressing and routing packets between different networks?",opts:["Data Link","Network","Transport","Session"],ans:[1],exp:"The Network layer (Layer 3) handles logical addressing using IP addresses and routes packets between networks."},
  {id:"1-002",domain:"1.0",sub:"1.1",type:"single",q:"A network technician discovers the problem is with MAC address resolution. Which OSI layer is most likely involved?",opts:["Physical","Data Link","Network","Transport"],ans:[1],exp:"The Data Link layer (Layer 2) handles MAC addressing and frame delivery on a local segment."},
  {id:"1-003",domain:"1.0",sub:"1.1",type:"single",q:"Which OSI layer handles encryption, data formatting, and character encoding conversion?",opts:["Application","Presentation","Session","Transport"],ans:[1],exp:"The Presentation layer (Layer 6) handles data formatting, encryption/decryption, and encoding conversions."},
  {id:"1-004",domain:"1.0",sub:"1.1",type:"multi",q:"Which protocols operate at the Transport layer (Layer 4) of the OSI model? (Choose TWO)",opts:["TCP","IP","UDP","Ethernet"],ans:[0,2],exp:"TCP and UDP both operate at the Transport layer. IP is at Network layer, Ethernet at Data Link."},
  {id:"1-005",domain:"1.0",sub:"1.1",type:"single",q:"A switch forwards traffic based on MAC addresses. At which OSI layer does a standard switch primarily operate?",opts:["Layer 1","Layer 2","Layer 3","Layer 4"],ans:[1],exp:"A standard switch operates at Layer 2 (Data Link) and forwards frames based on MAC addresses."},
  {id:"1-006",domain:"1.0",sub:"1.1",type:"single",q:"Which OSI layer is responsible for dialogue control between two communicating end systems?",opts:["Physical","Network","Transport","Session"],ans:[3],exp:"The Session layer (Layer 5) manages communication sessions—starting, stopping, and restarting dialogues between applications."},
  {id:"1-007",domain:"1.0",sub:"1.1",type:"single",q:"At which OSI layer does a protocol add both a header AND a footer to data, creating a frame?",opts:["Physical","Data Link","Network","Transport"],ans:[1],exp:"The Data Link layer adds both a header (with MAC addresses) and a trailer/footer (with FCS/CRC) to create a frame."},
  {id:"1-008",domain:"1.0",sub:"1.1",type:"single",q:"Which OSI layer defines the physical medium, network interfaces, connectors, and signaling methods?",opts:["Physical","Data Link","Network","Session"],ans:[0],exp:"The Physical layer (Layer 1) defines cables, connectors, signaling, and electrical/optical specifications."},
  {id:"1-009",domain:"1.0",sub:"1.1",type:"single",q:"The Internet Protocol (IP) operates at which OSI layer and is it connection-oriented or connectionless?",opts:["Network; connection-oriented","Network; connectionless","Transport; connection-oriented","Transport; connectionless"],ans:[1],exp:"IP operates at the Network layer and is connectionless—it provides no guarantee of delivery or ordering."},
  {id:"1-010",domain:"1.0",sub:"1.1",type:"single",q:"Which OSI layer uses port numbers to identify source and destination applications?",opts:["Application","Session","Transport","Network"],ans:[2],exp:"The Transport layer uses port numbers to identify which application should receive the data."},
  {id:"1-011",domain:"1.0",sub:"1.1",type:"single",q:"An Ethernet network interface adapter provides functions spanning which two OSI layers?",opts:["Physical and Data Link","Data Link and Network","Network and Transport","Transport and Application"],ans:[0],exp:"A NIC spans the Physical layer (signaling/cabling) and Data Link layer (MAC addressing/framing)."},
  {id:"1-012",domain:"1.0",sub:"1.1",type:"multi",q:"Which OSI layers do NOT have dedicated TCP/IP protocols exclusively for them? (Choose TWO)",opts:["Physical","Session","Presentation","Network"],ans:[1,2],exp:"The Session and Presentation layers don't have dedicated TCP/IP protocols. Their functions are handled by the Application layer in TCP/IP."},
  {id:"1-013",domain:"1.0",sub:"1.1",type:"single",q:"Which is the correct order of OSI layers from top to bottom?",opts:["Physical, Data Link, Network, Transport, Session, Presentation, Application","Application, Presentation, Session, Transport, Network, Data Link, Physical","Application, Session, Presentation, Transport, Network, Data Link, Physical","Session, Application, Presentation, Transport, Data Link, Network, Physical"],ans:[1],exp:"Top to bottom: Application (7), Presentation (6), Session (5), Transport (4), Network (3), Data Link (2), Physical (1). Remember: All People Seem To Need Data Processing."},
  {id:"1-014",domain:"1.0",sub:"1.1",type:"multi",q:"Which devices run exclusively at the Physical layer? (Choose TWO)",opts:["Routers","Repeaters","Hubs","Switches"],ans:[1,2],exp:"Repeaters and hubs are purely Physical layer devices that regenerate/repeat signals. Switches work at Data Link, routers at Network."},
  {id:"1-015",domain:"1.0",sub:"1.1",type:"single",q:"Which device enables communication between two computers using different protocols at EVERY layer of the OSI model?",opts:["Router","Hub","Switch","Gateway"],ans:[3],exp:"A gateway can translate between completely different protocol stacks, performing conversion at all OSI layers."},
  {id:"1-016",domain:"1.0",sub:"1.1",type:"single",q:"On a TCP/IP network, flow control is implemented at which OSI layer?",opts:["Presentation","Session","Transport","Network"],ans:[2],exp:"Flow control (managing the rate of data transmission) is a Transport layer function, handled by TCP."},

  // --- 1.2 Networking Appliances & Functions ---
  {id:"1-017",domain:"1.0",sub:"1.2",type:"single",q:"Which device operates at OSI Layer 3 and routes traffic between IP subnets?",opts:["Hub","Switch","Router","Access Point"],ans:[2],exp:"A router operates at Layer 3 and routes traffic between different IP subnets using IP addresses."},
  {id:"1-018",domain:"1.0",sub:"1.2",type:"single",q:"Which device sits between users and the external network, receiving requests and forwarding them on behalf of the client?",opts:["Router","Firewall","Proxy server","Load balancer"],ans:[2],exp:"A proxy server forwards client requests to external servers, providing caching, filtering, and security."},
  {id:"1-019",domain:"1.0",sub:"1.2",type:"single",q:"What is the primary difference between an IDS and an IPS?",opts:["IDS is hardware; IPS is software","IDS detects and alerts; IPS detects and blocks","IDS works at Layer 3; IPS at Layer 7","IDS uses signatures; IPS uses heuristics"],ans:[1],exp:"IDS monitors and alerts; IPS actively blocks malicious traffic in addition to detecting it."},
  {id:"1-020",domain:"1.0",sub:"1.2",type:"single",q:"A company needs to distribute web traffic across multiple servers. Which device should they implement?",opts:["Proxy server","Load balancer","VPN concentrator","Content filter"],ans:[1],exp:"A load balancer distributes traffic across multiple servers for performance and redundancy."},
  {id:"1-021",domain:"1.0",sub:"1.2",type:"single",q:"Which storage type provides block-level access and appears as a locally attached drive?",opts:["NAS","SAN","CDN","DAS"],ans:[1],exp:"A SAN provides block-level storage access. NAS provides file-level access through protocols like NFS/CIFS."},
  {id:"1-022",domain:"1.0",sub:"1.2",type:"single",q:"A NAS device is most closely associated with which of the following?",opts:["Failover cluster","File server","JBOD","RAID"],ans:[1],exp:"NAS provides file-level storage access similar to a file server, sharing files via NFS, CIFS/SMB protocols."},
  {id:"1-023",domain:"1.0",sub:"1.2",type:"multi",q:"Which SAN protocols can share a network with standard LAN traffic? (Choose TWO)",opts:["iSCSI","Fibre Channel","FCoE","InfiniBand"],ans:[0,2],exp:"iSCSI runs over standard IP/Ethernet networks, and FCoE runs over standard Ethernet. Fibre Channel requires its own dedicated infrastructure."},
  {id:"1-024",domain:"1.0",sub:"1.2",type:"single",q:"Which type of switch immediately forwards frames after reading only the destination address?",opts:["Cut-through","Source route","Store-and-forward","Fragment-free"],ans:[0],exp:"Cut-through switching forwards frames immediately after reading just the destination MAC address, providing the lowest latency."},
  {id:"1-025",domain:"1.0",sub:"1.2",type:"single",q:"Which device is a multiport bridge?",opts:["Router","Switch","Hub","Gateway"],ans:[1],exp:"A switch is essentially a multiport bridge—it learns MAC addresses and forwards frames only to the appropriate port."},
  {id:"1-026",domain:"1.0",sub:"1.2",type:"single",q:"A proxy server operates at which layer of the OSI model?",opts:["Data Link","Network","Transport","Application"],ans:[3],exp:"Proxy servers operate at the Application layer, understanding and filtering application-level protocols like HTTP."},
  {id:"1-027",domain:"1.0",sub:"1.2",type:"single",q:"Which feature distinguishes a next-generation firewall (NGFW) from a traditional firewall?",opts:["Stateful packet inspection","Deep packet inspection (DPI)","NAT support","VPN support"],ans:[1],exp:"NGFWs add deep packet inspection (DPI), application awareness, and integrated IPS beyond traditional stateful inspection."},
  {id:"1-028",domain:"1.0",sub:"1.2",type:"single",q:"What is the abbreviation for a network of Internet datacenters supplying end users with localized access to content?",opts:["CDN","QoS","NAS","SAN"],ans:[0],exp:"A CDN (Content Delivery Network) uses geographically distributed servers to deliver content to users from nearby locations."},
  {id:"1-029",domain:"1.0",sub:"1.2",type:"single",q:"Which prevents packets on a TCP/IP network from being transmitted endlessly from router to router?",opts:["OSPF","MTU","Administrative distance","TTL (Time to Live)"],ans:[3],exp:"TTL decreases by 1 at each router hop. When it reaches 0, the packet is dropped, preventing infinite loops."},
  {id:"1-030",domain:"1.0",sub:"1.2",type:"multi",q:"Which statements about switches and routers are true? (Choose TWO)",opts:["Routers operate at Network layer; switches at Data Link","All devices on a switch share separate broadcast domains","Switches forward based on MAC; routers based on IP","Routers cannot share routing information with each other"],ans:[0,2],exp:"Routers work at Layer 3 (IP), switches at Layer 2 (MAC). All ports on a switch share one broadcast domain unless VLANs are used."},
  {id:"1-031",domain:"1.0",sub:"1.2",type:"single",q:"Which device enables administrators to manage multiple wireless access points from a central location?",opts:["Hypervisor","Wireless controller","Wireless endpoint","Demarcation point"],ans:[1],exp:"A wireless LAN controller provides centralized management of access points—configuration, monitoring, and deployment."},
  {id:"1-032",domain:"1.0",sub:"1.2",type:"single",q:"Which of the following is the true definition of the term 'modem'?",opts:["A device connecting a computer to the PSTN","A device connecting a LAN to the Internet","A device that converts analog signals to digital and back","A device connecting a LAN to a WAN"],ans:[2],exp:"Modem = modulator/demodulator. It converts between analog and digital signals regardless of the medium."},

  // --- 1.3 Cloud Concepts ---
  {id:"1-033",domain:"1.0",sub:"1.3",type:"single",q:"Which cloud service model provides the MOST control over the underlying infrastructure?",opts:["SaaS","PaaS","IaaS","DaaS"],ans:[2],exp:"IaaS gives you control over OS, storage, and deployed applications. PaaS manages the platform; SaaS manages everything."},
  {id:"1-034",domain:"1.0",sub:"1.3",type:"single",q:"When you contract with a provider to obtain email services using their servers in the public cloud, which service model are you using?",opts:["IaaS","PaaS","SaaS","DaaS"],ans:[2],exp:"Using a provider's complete email application is Software as a Service (SaaS)—no infrastructure management needed."},
  {id:"1-035",domain:"1.0",sub:"1.3",type:"single",q:"A company uses both on-premises servers and public cloud resources. What type of deployment is this?",opts:["Public cloud","Private cloud","Hybrid cloud","Community cloud"],ans:[2],exp:"Hybrid cloud combines private and public cloud resources with workloads able to move between them."},
  {id:"1-036",domain:"1.0",sub:"1.3",type:"single",q:"Which cloud concept describes automatically scaling resources up or down based on demand?",opts:["Multitenancy","Scalability","Elasticity","Redundancy"],ans:[2],exp:"Elasticity is automatic, dynamic scaling. Scalability is the ability to grow but doesn't imply automatic adjustment."},
  {id:"1-037",domain:"1.0",sub:"1.3",type:"single",q:"What is a Virtual Private Cloud (VPC)?",opts:["A VPN tunnel to the cloud","A pool of isolated resources in a public cloud","A private datacenter","An encrypted cloud storage volume"],ans:[1],exp:"A VPC provides logically isolated resources within a public cloud with your own IP space and security controls."},
  {id:"1-038",domain:"1.0",sub:"1.3",type:"single",q:"In which cloud model can a single organization function as both provider AND consumer of all cloud services?",opts:["Public cloud","Private cloud","Hybrid cloud","Multicloud"],ans:[1],exp:"In a private cloud, the organization owns and operates all infrastructure for its own exclusive use."},
  {id:"1-039",domain:"1.0",sub:"1.3",type:"single",q:"Ed's company website is overwhelmed, so he spins up public cloud VMs to handle overflow. What is this called?",opts:["Cloud busting","Cloud bursting","Cloud splitting","Cloud migrating"],ans:[1],exp:"Cloud bursting is when traffic overflows from a private cloud to a public cloud during demand spikes."},
  {id:"1-040",domain:"1.0",sub:"1.3",type:"single",q:"Ed needs a cloud provider to furnish a fully configured Windows server for his application. Which service model?",opts:["IaaS","PaaS","SaaS","DaaS"],ans:[1],exp:"PaaS provides a pre-configured platform (including OS) where you deploy your own applications."},
  {id:"1-041",domain:"1.0",sub:"1.3",type:"single",q:"Which cloud connection option provides a dedicated high-speed physical connection bypassing the public Internet?",opts:["VPN","Direct Connect","SD-WAN","MPLS"],ans:[1],exp:"Direct Connect provides a dedicated private connection between your network and the cloud provider, avoiding Internet bottlenecks."},

  // --- 1.4 Ports, Protocols, Services ---
  {id:"1-042",domain:"1.0",sub:"1.4",type:"single",q:"Which protocol uses port 22 for encrypted console communication?",opts:["Telnet","SSH","FTP","SMTP"],ans:[1],exp:"SSH uses TCP port 22 for encrypted remote access. Telnet (port 23) is unencrypted."},
  {id:"1-043",domain:"1.0",sub:"1.4",type:"single",q:"SFTP provides secure file transfers using which port?",opts:["Port 20","Port 21","Port 22","Port 69"],ans:[2],exp:"SFTP uses SSH on port 22 for encrypted file transfers. FTP uses 20/21 (unencrypted), TFTP uses 69."},
  {id:"1-044",domain:"1.0",sub:"1.4",type:"single",q:"Which port does HTTPS use for encrypted web communication?",opts:["80","443","8080","8443"],ans:[1],exp:"HTTPS uses TCP port 443 with TLS/SSL encryption. HTTP uses port 80."},
  {id:"1-045",domain:"1.0",sub:"1.4",type:"single",q:"DHCP automatically assigns IP configuration using which ports?",opts:["TCP 53/UDP 53","UDP 67/UDP 68","TCP 80/TCP 443","UDP 161/UDP 162"],ans:[1],exp:"DHCP uses UDP port 67 (server) and UDP port 68 (client) to automatically assign IP addresses and configuration."},
  {id:"1-046",domain:"1.0",sub:"1.4",type:"single",q:"DNS uses which port number(s) for name resolution?",opts:["TCP/UDP 53","UDP 67/68","TCP 25","TCP 389"],ans:[0],exp:"DNS uses both UDP port 53 (standard queries) and TCP port 53 (zone transfers and large responses)."},
  {id:"1-047",domain:"1.0",sub:"1.4",type:"single",q:"SMTP for sending email with TLS encryption uses which port?",opts:["25","110","143","587"],ans:[3],exp:"SMTPS uses TCP port 587 for encrypted email submission. Port 25 is for plaintext SMTP relay."},
  {id:"1-048",domain:"1.0",sub:"1.4",type:"single",q:"SNMP uses which port for polling network devices?",opts:["UDP 123","UDP 161","UDP 514","TCP 389"],ans:[1],exp:"SNMP uses UDP port 161 for queries/polling and UDP port 162 for traps (alerts from devices)."},
  {id:"1-049",domain:"1.0",sub:"1.4",type:"single",q:"LDAPS (LDAP over SSL) uses which port?",opts:["TCP 389","TCP 443","TCP 636","TCP 3389"],ans:[2],exp:"LDAPS uses TCP port 636. Standard LDAP uses TCP port 389 without encryption."},
  {id:"1-050",domain:"1.0",sub:"1.4",type:"single",q:"RDP uses which port for remote desktop connections?",opts:["TCP 22","TCP 443","TCP 3389","TCP 5060"],ans:[2],exp:"RDP (Remote Desktop Protocol) uses TCP port 3389 for graphical remote desktop access."},
  {id:"1-051",domain:"1.0",sub:"1.4",type:"single",q:"SIP (Session Initiation Protocol) for VoIP uses which ports?",opts:["TCP 80/443","TCP/UDP 5060-5061","UDP 161/162","TCP 1433"],ans:[1],exp:"SIP uses TCP/UDP ports 5060 (unencrypted) and 5061 (encrypted) for VoIP call setup and management."},
  {id:"1-052",domain:"1.0",sub:"1.4",type:"single",q:"SMB (Server Message Block) for Windows file sharing uses which port?",opts:["TCP 139","TCP 445","TCP 389","TCP 514"],ans:[1],exp:"SMB uses TCP port 445 for direct file and printer sharing over TCP (NetBIOS-less)."},
  {id:"1-053",domain:"1.0",sub:"1.4",type:"single",q:"NTP synchronizes clocks on which port?",opts:["UDP 53","UDP 69","UDP 123","UDP 514"],ans:[2],exp:"NTP (Network Time Protocol) uses UDP port 123 to synchronize clocks across network devices."},
  {id:"1-054",domain:"1.0",sub:"1.4",type:"single",q:"Syslog sends log messages on which port?",opts:["UDP 161","UDP 162","UDP 514","TCP 1433"],ans:[2],exp:"Syslog uses UDP port 514 for centralized message logging from network devices."},
  {id:"1-055",domain:"1.0",sub:"1.4",type:"single",q:"SQL Server databases use which default port?",opts:["TCP 443","TCP 636","TCP 1433","TCP 3389"],ans:[2],exp:"Microsoft SQL Server uses TCP port 1433 by default for database connections."},
  {id:"1-056",domain:"1.0",sub:"1.4",type:"multi",q:"Which are connectionless protocols? (Choose TWO)",opts:["TCP","UDP","ICMP","SFTP"],ans:[1,2],exp:"UDP and ICMP are connectionless. TCP is connection-oriented with three-way handshake. SFTP runs over TCP (SSH)."},
  {id:"1-057",domain:"1.0",sub:"1.4",type:"single",q:"What traffic type sends data to ALL hosts on a network segment?",opts:["Unicast","Multicast","Broadcast","Anycast"],ans:[2],exp:"Broadcast = one-to-all on local segment. Unicast = one-to-one. Multicast = one-to-subscribed-many. Anycast = one-to-nearest."},
  {id:"1-058",domain:"1.0",sub:"1.4",type:"single",q:"Which traffic type delivers packets to the nearest of multiple destinations sharing the same address?",opts:["Unicast","Multicast","Broadcast","Anycast"],ans:[3],exp:"Anycast routes to the geographically nearest destination, commonly used for DNS root servers and CDNs."},
  {id:"1-059",domain:"1.0",sub:"1.4",type:"single",q:"Which IPSec protocol provides both authentication AND encryption?",opts:["AH","ESP","IKE","GRE"],ans:[1],exp:"ESP provides encryption and authentication. AH provides authentication only. IKE handles key exchange."},
  {id:"1-060",domain:"1.0",sub:"1.4",type:"single",q:"IKE (Internet Key Exchange) for IPSec negotiation uses which port?",opts:["TCP 443","UDP 500","TCP 636","UDP 4500"],ans:[1],exp:"IKE uses UDP port 500 to negotiate encryption/decryption keys and build Security Associations for IPSec."},
  {id:"1-061",domain:"1.0",sub:"1.4",type:"single",q:"TFTP uses which transport protocol and port?",opts:["TCP/20","TCP/21","UDP/69","UDP/53"],ans:[2],exp:"TFTP uses UDP port 69. It's a simple file transfer protocol with no authentication—useful for booting and firmware updates."},

  // --- 1.5 Transmission Media & Transceivers ---
  {id:"1-062",domain:"1.0",sub:"1.5",type:"single",q:"Which fiber type uses a laser and can transmit up to 100 km?",opts:["Multimode","Single-mode","Twinaxial","Coaxial"],ans:[1],exp:"Single-mode fiber uses a laser and small core for very long distances. Multimode uses LED and reaches ~2 km."},
  {id:"1-063",domain:"1.0",sub:"1.5",type:"single",q:"Maximum distance for 1000BASE-T copper Ethernet?",opts:["55 meters","100 meters","300 meters","2 km"],ans:[1],exp:"All twisted-pair Ethernet standards have a 100-meter maximum cable distance."},
  {id:"1-064",domain:"1.0",sub:"1.5",type:"single",q:"Which connector is small, uses a clip, and is common in high-density fiber installations?",opts:["SC","ST","LC","MPO"],ans:[2],exp:"LC (Local Connector) is small with clip retention, popular in high-density and single-mode installations."},
  {id:"1-065",domain:"1.0",sub:"1.5",type:"single",q:"QSFP combines how many channels into a single transceiver?",opts:["2","4","8","16"],ans:[1],exp:"QSFP (Quad SFP) combines 4 channels. QSFP+ = 4x10 Gbps = 40 Gbps."},
  {id:"1-066",domain:"1.0",sub:"1.5",type:"single",q:"Which cable type is required in air handling plenum spaces?",opts:["PVC-jacketed","Plenum-rated (FEP)","Riser-rated","Outdoor direct burial"],ans:[1],exp:"Plenum-rated cable uses FEP that produces less toxic smoke. Building codes require it in air handling spaces."},
  {id:"1-067",domain:"1.0",sub:"1.5",type:"single",q:"Which connector type is used for coaxial cable television infrastructure?",opts:["RJ-45","RJ-11","F-type","BNC"],ans:[2],exp:"F-type connectors are threaded connectors used with coaxial cable for cable TV and cable modem connections (DOCSIS)."},
  {id:"1-068",domain:"1.0",sub:"1.5",type:"single",q:"The minimum cable category for 1000BASE-T is:",opts:["Cat 3","Cat 5","Cat 5e","Cat 6"],ans:[1],exp:"Cat 5 is the minimum for 1000BASE-T, though Cat 5e is recommended. Cat 6/6a supports 10GBASE-T."},
  {id:"1-069",domain:"1.0",sub:"1.5",type:"single",q:"RJ-45 connectors have how many positions and conductors?",opts:["4 position, 4 conductor","6 position, 2 conductor","8 position, 8 conductor","6 position, 4 conductor"],ans:[2],exp:"RJ-45 is 8P8C (8 position, 8 conductor), used for Ethernet. RJ-11 is 6P2C for telephone."},
  {id:"1-070",domain:"1.0",sub:"1.5",type:"single",q:"Which cable supports 10GBASE-T at 100 meters?",opts:["Cat 5e","Cat 6","Cat 6a","Cat 5"],ans:[2],exp:"Cat 6a supports 10GBASE-T at 100 meters. Cat 6 only supports it at 55 meters. Cat 5/5e don't support 10 Gbps."},

  // --- 1.6 Topologies & Architecture ---
  {id:"1-071",domain:"1.0",sub:"1.6",type:"single",q:"In a spine-and-leaf architecture, which statement is TRUE?",opts:["Leaf switches connect to each other","Spine switches connect to each other","Every leaf connects to every spine","Only some leaves connect to spines"],ans:[2],exp:"Every leaf connects to every spine; leaves never connect to leaves; spines never connect to spines."},
  {id:"1-072",domain:"1.0",sub:"1.6",type:"single",q:"Which topology provides the MOST redundancy?",opts:["Star","Bus","Full mesh","Ring"],ans:[2],exp:"Full mesh connects every device to every other device, providing maximum redundancy."},
  {id:"1-073",domain:"1.0",sub:"1.6",type:"single",q:"In three-tier architecture, end-user devices connect at which layer?",opts:["Core","Distribution","Access","Edge"],ans:[2],exp:"The Access layer is where end users connect. Distribution is the middle tier, Core is the backbone."},
  {id:"1-074",domain:"1.0",sub:"1.6",type:"single",q:"Traffic between devices within the same datacenter is called:",opts:["North-south traffic","East-west traffic","Upstream traffic","Backbone traffic"],ans:[1],exp:"East-west = intra-datacenter traffic. North-south = traffic entering/leaving the datacenter."},
  {id:"1-075",domain:"1.0",sub:"1.6",type:"single",q:"A collapsed core architecture combines which two layers?",opts:["Access and Distribution","Core and Distribution","Access and Core","Distribution and Application"],ans:[1],exp:"Collapsed core merges the Core and Distribution layers into a two-tier model—simpler and cheaper but less redundant."},
  {id:"1-076",domain:"1.0",sub:"1.6",type:"single",q:"Which topology allows expansion with the LEAST disruption to existing users?",opts:["Bus","Ring","Star/hub and spoke","Mesh"],ans:[2],exp:"Star topology—new devices connect to the central switch without disrupting other connections. Bus and ring require interruption."},

  // --- 1.7 IPv4 Addressing ---
  {id:"1-077",domain:"1.0",sub:"1.7",type:"single",q:"A host has IP 172.16.45.100/20. What is the subnet mask?",opts:["255.255.240.0","255.255.248.0","255.255.224.0","255.255.255.0"],ans:[0],exp:"/20 = 20 network bits. Third octet: 11110000 = 240. Mask = 255.255.240.0"},
  {id:"1-078",domain:"1.0",sub:"1.7",type:"single",q:"Which is a valid Class B private IP range?",opts:["10.0.0.0 - 10.255.255.255","172.16.0.0 - 172.31.255.255","192.168.0.0 - 192.168.255.255","169.254.0.0 - 169.254.255.255"],ans:[1],exp:"172.16.0.0/12 is the Class B private range (RFC 1918). 10.x is Class A, 192.168.x is Class C private."},
  {id:"1-079",domain:"1.0",sub:"1.7",type:"single",q:"A device gets IP 169.254.10.5. What does this indicate?",opts:["Private network address","DHCP assigned correctly","Failed to get DHCP address (APIPA)","Statically configured"],ans:[2],exp:"169.254.x.x = APIPA. The device couldn't reach a DHCP server and auto-assigned a link-local address."},
  {id:"1-080",domain:"1.0",sub:"1.7",type:"single",q:"How many usable hosts in a /26 subnet?",opts:["30","62","64","126"],ans:[1],exp:"/26 = 6 host bits. 2^6 = 64 total - 2 (network + broadcast) = 62 usable hosts."},
  {id:"1-081",domain:"1.0",sub:"1.7",type:"single",q:"How many usable hosts in a /28 subnet?",opts:["6","14","16","30"],ans:[1],exp:"/28 = 4 host bits. 2^4 = 16 total - 2 = 14 usable hosts."},
  {id:"1-082",domain:"1.0",sub:"1.7",type:"single",q:"The IP address 10.74.222.11 belongs to which class?",opts:["Class A","Class B","Class C","Class D"],ans:[0],exp:"Class A = 1-126 in first octet. 10.x.x.x falls in Class A range with default mask 255.0.0.0."},
  {id:"1-083",domain:"1.0",sub:"1.7",type:"single",q:"What is the loopback address used for self-testing?",opts:["0.0.0.0","127.0.0.1","169.254.0.1","255.255.255.255"],ans:[1],exp:"127.0.0.1 is the loopback address. The entire 127.x.x.x range is reserved for loopback testing."},
  {id:"1-084",domain:"1.0",sub:"1.7",type:"single",q:"CIDR notation /24 equals which subnet mask?",opts:["255.255.0.0","255.255.128.0","255.255.255.0","255.255.255.128"],ans:[2],exp:"/24 = 24 bits for network = 255.255.255.0. Each octet with all 1s = 255."},
  {id:"1-085",domain:"1.0",sub:"1.7",type:"single",q:"What is the network address for host 192.168.1.130/25?",opts:["192.168.1.0","192.168.1.128","192.168.1.64","192.168.1.192"],ans:[1],exp:"/25 splits into two subnets: .0-.127 and .128-.255. Host .130 falls in the 192.168.1.128 subnet."},

  // --- 1.8 Modern Network Environments ---
  {id:"1-086",domain:"1.0",sub:"1.8",type:"single",q:"SDN separates networking devices into which functional planes?",opts:["Fast and slow planes","Data, control, and management planes","Internal and external planes","Primary and backup planes"],ans:[1],exp:"SDN splits devices into data plane (forwarding), control plane (routing decisions), and management plane (configuration)."},
  {id:"1-087",domain:"1.0",sub:"1.8",type:"single",q:"VXLAN supports how many virtual networks?",opts:["4,094","16,000","Over 16 million","Unlimited"],ans:[2],exp:"VXLAN uses a 24-bit VNI allowing over 16 million virtual networks vs. VLAN's ~4,094."},
  {id:"1-088",domain:"1.0",sub:"1.8",type:"single",q:"In Zero Trust security, which statement is TRUE?",opts:["Internal users are trusted by default","Only external traffic is inspected","Nothing is inherently trusted; everything must be verified","VPN connections bypass verification"],ans:[2],exp:"Zero Trust = never trust, always verify. Every device, user, and process must be authenticated."},
  {id:"1-089",domain:"1.0",sub:"1.8",type:"single",q:"IPv6 addresses are how many bits?",opts:["32","64","96","128"],ans:[3],exp:"IPv6 uses 128-bit addresses (vs. IPv4's 32 bits), providing a vastly larger address space."},
  {id:"1-090",domain:"1.0",sub:"1.8",type:"single",q:"Which IPv6 transition mechanism encapsulates IPv6 inside IPv4 packets?",opts:["NAT64","Dual-stack","6to4 tunneling","DHCPv6"],ans:[2],exp:"6to4 tunneling encapsulates IPv6 packets within IPv4 for transit across IPv4 networks. Dual-stack runs both simultaneously."},

  // ═══════════════════════════════════════════════════════════════════════════
  // DOMAIN 2.0: NETWORK IMPLEMENTATION (20% of exam) — ~60 questions
  // ═══════════════════════════════════════════════════════════════════════════

  // --- 2.1 Routing ---
  {id:"2-001",domain:"2.0",sub:"2.1",type:"single",q:"OSPF is what type of routing protocol?",opts:["Distance-vector","Link-state","Hybrid","Path-vector"],ans:[1],exp:"OSPF is an open-standard link-state protocol. It builds a complete topology map and uses Dijkstra's algorithm for shortest path."},
  {id:"2-002",domain:"2.0",sub:"2.1",type:"single",q:"EIGRP has an administrative distance of:",opts:["90","110","120","1"],ans:[0],exp:"EIGRP = 90, OSPF = 110, RIP = 120, Static = 1, Connected = 0. Lower AD = more trusted."},
  {id:"2-003",domain:"2.0",sub:"2.1",type:"single",q:"PAT maps multiple private addresses to one public address using:",opts:["MAC addresses","IP addresses only","Port numbers","VLAN tags"],ans:[2],exp:"PAT (Port Address Translation) tracks connections using unique source port numbers to map many-to-one."},
  {id:"2-004",domain:"2.0",sub:"2.1",type:"single",q:"A router has routes via OSPF (AD 110) and EIGRP (AD 90) to the same destination. Which wins?",opts:["OSPF","EIGRP","Both equally","Depends on metric"],ans:[1],exp:"Lower administrative distance wins. EIGRP (90) < OSPF (110), so the EIGRP route is installed."},
  {id:"2-005",domain:"2.0",sub:"2.1",type:"single",q:"BGP is classified as what type of routing protocol?",opts:["Interior gateway protocol","Exterior gateway protocol","Link-state protocol","Distance-vector protocol"],ans:[1],exp:"BGP is an exterior gateway protocol used to route between autonomous systems (the backbone of Internet routing)."},
  {id:"2-006",domain:"2.0",sub:"2.1",type:"single",q:"Static routing has an administrative distance of:",opts:["0","1","90","110"],ans:[1],exp:"Static routes have AD of 1 (directly connected = 0). They're highly trusted but require manual configuration."},
  {id:"2-007",domain:"2.0",sub:"2.1",type:"single",q:"Which routing protocol is partly proprietary to Cisco and uses DUAL algorithm?",opts:["OSPF","RIPv2","EIGRP","BGP"],ans:[2],exp:"EIGRP is partly Cisco proprietary and uses the Diffusing Update Algorithm (DUAL) for loop-free routing."},
  {id:"2-008",domain:"2.0",sub:"2.1",type:"single",q:"FHRP protocols use virtual IP addresses to provide what?",opts:["Load balancing","Default gateway redundancy","VLAN segmentation","DNS resolution"],ans:[1],exp:"FHRP (HSRP, VRRP, GLBP) provides default gateway redundancy—if one router fails, another takes over the virtual IP."},
  {id:"2-009",domain:"2.0",sub:"2.1",type:"single",q:"When a route to the destination doesn't exist, the router sends which ICMP message?",opts:["Time Exceeded","Destination Unreachable","Redirect","Echo Reply"],ans:[1],exp:"ICMP Destination Unreachable is sent when no route exists. Time Exceeded occurs when TTL reaches 0."},
  {id:"2-010",domain:"2.0",sub:"2.1",type:"single",q:"A default route is configured as a route to which destination?",opts:["127.0.0.1","255.255.255.255","0.0.0.0/0","10.0.0.0/8"],ans:[2],exp:"0.0.0.0/0 is the default route—it matches all destinations. Used as gateway of last resort when no specific route exists."},

  // --- 2.2 Switching ---
  {id:"2-011",domain:"2.0",sub:"2.2",type:"single",q:"RSTP prevents switching loops. What IEEE standard is it?",opts:["802.1D","802.1Q","802.1w","802.1X"],ans:[2],exp:"RSTP is IEEE 802.1w with convergence in ~6 seconds. Original STP (802.1D) took 30-50 seconds."},
  {id:"2-012",domain:"2.0",sub:"2.2",type:"single",q:"802.1Q adds what to Ethernet frames on trunk links?",opts:["Encryption","VLAN tag","IP header","MAC trailer"],ans:[1],exp:"802.1Q inserts a 4-byte VLAN tag into Ethernet frames on trunk links to identify VLAN membership."},
  {id:"2-013",domain:"2.0",sub:"2.2",type:"single",q:"What carries untagged frames across a trunk link?",opts:["Management VLAN","Voice VLAN","Native VLAN","Default gateway"],ans:[2],exp:"The native VLAN carries untagged frames on a trunk. It should match on both ends to prevent issues."},
  {id:"2-014",domain:"2.0",sub:"2.2",type:"single",q:"LACP combines multiple physical interfaces into one logical interface for:",opts:["Security","Increased bandwidth and redundancy","VLAN isolation","QoS prioritization"],ans:[1],exp:"LACP (Link Aggregation Control Protocol) bonds multiple links for aggregate bandwidth and link redundancy."},
  {id:"2-015",domain:"2.0",sub:"2.2",type:"single",q:"VLAN IDs use how many bits, allowing approximately how many VLANs?",opts:["8 bits, 256 VLANs","12 bits, 4094 VLANs","16 bits, 65535 VLANs","24 bits, 16 million VLANs"],ans:[1],exp:"VLAN IDs are 12 bits = 4,094 usable VLANs (0 and 4095 are reserved). Extended range: 1006-4094."},
  {id:"2-016",domain:"2.0",sub:"2.2",type:"single",q:"Which STP port state means the port is fully operational and forwarding traffic?",opts:["Blocking","Listening","Learning","Forwarding"],ans:[3],exp:"STP states: Blocking → Listening → Learning → Forwarding → Disabled. Only Forwarding passes data."},
  {id:"2-017",domain:"2.0",sub:"2.2",type:"single",q:"A jumbo frame has an Ethernet payload exceeding:",opts:["64 bytes","512 bytes","1,500 bytes","9,000 bytes"],ans:[2],exp:"Standard Ethernet max payload is 1,500 bytes. Jumbo frames exceed this, typically up to 9,000 bytes MTU."},
  {id:"2-018",domain:"2.0",sub:"2.2",type:"single",q:"Port mirroring copies traffic from one port to another for what purpose?",opts:["Load balancing","Packet capture and analysis","Redundancy","VLAN trunking"],ans:[1],exp:"Port mirroring (SPAN) copies traffic to a monitoring port for packet capture, IDS analysis, or troubleshooting."},

  // --- 2.3 Wireless ---
  {id:"2-019",domain:"2.0",sub:"2.3",type:"single",q:"802.11ax (Wi-Fi 6/6E) operates on which frequencies?",opts:["2.4 GHz only","5 GHz only","2.4 and 5 GHz","2.4, 5, and 6 GHz"],ans:[3],exp:"802.11ax operates on 2.4, 5, and 6 GHz. The 6 GHz band is the '6E' designation."},
  {id:"2-020",domain:"2.0",sub:"2.3",type:"single",q:"WPA3 uses which encryption protocol?",opts:["TKIP","CCMP/AES","GCMP","RC4"],ans:[2],exp:"WPA3 uses GCMP (Galois/Counter Mode Protocol). WPA2 uses CCMP/AES. WPA used TKIP. WEP used RC4."},
  {id:"2-021",domain:"2.0",sub:"2.3",type:"single",q:"WPA2-Enterprise authenticates users through:",opts:["Pre-shared key","RADIUS server","MAC filtering","WPS"],ans:[1],exp:"WPA2-Enterprise (802.1X) uses RADIUS for individual user authentication. WPA2-Personal uses a shared PSK."},
  {id:"2-022",domain:"2.0",sub:"2.3",type:"single",q:"Band steering directs clients to which frequency?",opts:["Always 2.4 GHz","The optimal/less congested band","Always 6 GHz","Wired connection"],ans:[1],exp:"Band steering pushes capable devices to the better frequency (typically 5 GHz over 2.4 GHz)."},
  {id:"2-023",domain:"2.0",sub:"2.3",type:"single",q:"802.11ac (Wi-Fi 5) operates on which frequency?",opts:["2.4 GHz only","5 GHz only","2.4 and 5 GHz","6 GHz only"],ans:[1],exp:"802.11ac operates exclusively on 5 GHz. 802.11n was the first to use both 2.4 and 5 GHz."},
  {id:"2-024",domain:"2.0",sub:"2.3",type:"single",q:"Which wireless mode has devices communicate directly without an access point?",opts:["Infrastructure","Ad hoc (IBSS)","Mesh","Point-to-multipoint"],ans:[1],exp:"Ad hoc (Independent Basic Service Set) allows direct peer-to-peer wireless communication without an AP."},
  {id:"2-025",domain:"2.0",sub:"2.3",type:"single",q:"The hardware MAC address of a wireless access point is called the:",opts:["SSID","ESSID","BSSID","WPS"],ans:[2],exp:"BSSID (Basic Service Set Identifier) is the MAC address of the access point's radio interface."},
  {id:"2-026",domain:"2.0",sub:"2.3",type:"single",q:"A Yagi antenna is what type?",opts:["Omnidirectional","Directional with high gain","Parabolic","Isotropic"],ans:[1],exp:"Yagi antennas are highly directional with high gain, focusing signal in one direction for increased range."},
  {id:"2-027",domain:"2.0",sub:"2.3",type:"single",q:"Which feature uses 802.11h to avoid frequency conflict with radar/satellite?",opts:["Band steering","DFS (Dynamic Frequency Selection)","MIMO","Beamforming"],ans:[1],exp:"DFS allows an AP to switch to an unused frequency to avoid conflict with radar and satellite systems."},
  {id:"2-028",domain:"2.0",sub:"2.3",type:"single",q:"A captive portal is commonly used for:",opts:["VPN encryption","Guest network authentication","VLAN trunking","DNS resolution"],ans:[1],exp:"Captive portals redirect unauthenticated users to a login page, commonly for guest/public Wi-Fi access."},

  // --- 2.4 Physical Installation ---
  {id:"2-029",domain:"2.0",sub:"2.4",type:"single",q:"Standard network rack width is:",opts:["15 inches","19 inches","23 inches","42 inches"],ans:[1],exp:"Standard rack width = 19 inches. Height measured in rack units (1U = 1.75 inches). Common height = 42U."},
  {id:"2-030",domain:"2.0",sub:"2.4",type:"single",q:"The MDF (Main Distribution Frame) is typically located in the:",opts:["Server room closest to each user","Central datacenter","Each floor's wiring closet","The ISP building"],ans:[1],exp:"The MDF is the central point of the network, usually in the main datacenter, connecting WAN links and IDFs."},
  {id:"2-031",domain:"2.0",sub:"2.4",type:"single",q:"IDFs extend the MDF by connecting users at:",opts:["Remote offices only","Strategic distribution points closer to users","The Internet edge","Cloud datacenters"],ans:[1],exp:"IDFs (Intermediate Distribution Frames) are strategic distribution points connecting users to the MDF via uplinks."},
  {id:"2-032",domain:"2.0",sub:"2.4",type:"single",q:"Recommended datacenter humidity range is:",opts:["10-20%","30-35%","40-60%","70-80%"],ans:[2],exp:"40-60% humidity. Too low = static discharge risk. Too high = condensation/corrosion risk."},
  {id:"2-033",domain:"2.0",sub:"2.4",type:"single",q:"Recommended datacenter temperature range is:",opts:["40-50°F","64-81°F","85-95°F","32-45°F"],ans:[1],exp:"Industry best practice is 64-81°F (18-27°C) for datacenter equipment operating temperature."},
  {id:"2-034",domain:"2.0",sub:"2.4",type:"single",q:"A UPS provides what type of protection?",opts:["Long-term power generation","Short-term backup power during outages","Surge protection only","Power distribution only"],ans:[1],exp:"A UPS (Uninterruptible Power Supply) provides short-term backup power during blackouts, brownouts, and surges."},

  // ═══════════════════════════════════════════════════════════════════════════
  // DOMAIN 3.0: NETWORK OPERATIONS (19% of exam) — ~55 questions
  // ═══════════════════════════════════════════════════════════════════════════

  {id:"3-001",domain:"3.0",sub:"3.1",type:"single",q:"An SLA defines minimum acceptable:",opts:["Security policies","Uptime, response time, and performance metrics","Hardware specifications","Employee access levels"],ans:[1],exp:"SLAs define minimum service terms between provider and customer—uptime, response time, remediation."},
  {id:"3-002",domain:"3.0",sub:"3.1",type:"single",q:"EOL vs EOS: which stops security patches and updates?",opts:["Both simultaneously","EOL only","EOS only","Neither"],ans:[2],exp:"EOS (End of Support) = no more patches/updates/support. EOL = manufacturer stops selling but may still support."},
  {id:"3-003",domain:"3.0",sub:"3.1",type:"single",q:"What determines existing wireless conditions including signal strength and interference?",opts:["Packet capture","Site survey","Vulnerability scan","Penetration test"],ans:[1],exp:"A wireless site survey maps signal coverage, identifies interference sources, and determines optimal AP placement."},
  {id:"3-004",domain:"3.0",sub:"3.1",type:"single",q:"Change management is important because:",opts:["It eliminates all network risks","Changes are a common source of network problems","It speeds up deployments","It reduces hardware costs"],ans:[1],exp:"Changes are one of the most common risk factors in enterprise networks. Change management controls the process."},
  {id:"3-005",domain:"3.0",sub:"3.1",type:"single",q:"A baseline configuration ensures:",opts:["Maximum performance","All systems follow a defined standard","Unlimited user access","Zero downtime"],ans:[1],exp:"Baseline/golden configurations define the standard settings all systems must follow—OS versions, patches, firewall rules."},
  {id:"3-006",domain:"3.0",sub:"3.2",type:"single",q:"SNMP uses a MIB database containing:",opts:["User credentials","Object Identifiers (OIDs)","Routing tables","VLAN assignments"],ans:[1],exp:"MIB contains OIDs—unique identifiers for every manageable object on network devices."},
  {id:"3-007",domain:"3.0",sub:"3.2",type:"single",q:"Which SNMP version provides authentication AND encryption?",opts:["v1","v2c","v3","All versions"],ans:[2],exp:"SNMPv3 adds message integrity, authentication, and encryption. v1 and v2c send community strings in clear text."},
  {id:"3-008",domain:"3.0",sub:"3.2",type:"single",q:"SNMP traps communicate on which port?",opts:["UDP 161","UDP 162","TCP 514","TCP 389"],ans:[1],exp:"SNMP traps (unsolicited alerts from devices) use UDP port 162. Standard SNMP queries use UDP 161."},
  {id:"3-009",domain:"3.0",sub:"3.2",type:"single",q:"A SIEM aggregates security logs for:",opts:["Device configuration","Correlation, alerting, and forensic analysis","IP address management","Routing optimization"],ans:[1],exp:"SIEM collects logs from many sources, correlates events in real-time, generates alerts, and supports forensic investigation."},
  {id:"3-010",domain:"3.0",sub:"3.2",type:"single",q:"NetFlow collects data about:",opts:["Wireless signal strength","Network traffic flows and statistics","Physical cable runs","DNS records"],ans:[1],exp:"NetFlow gathers traffic flow statistics including source/destination IPs, ports, protocols, and byte counts."},
  {id:"3-011",domain:"3.0",sub:"3.3",type:"single",q:"A hot site provides:",opts:["Empty building space","Hardware but no data","Fully operational duplicate with real-time replication","Partial equipment only"],ans:[2],exp:"Hot site = fully operational mirror with real-time data. Warm = hardware ready, needs data. Cold = empty facility."},
  {id:"3-012",domain:"3.0",sub:"3.3",type:"single",q:"RPO defines:",opts:["Time to restore service","Maximum acceptable data loss (in time)","Average repair duration","Time between failures"],ans:[1],exp:"RPO = max acceptable data loss. RTO = target time to restore. MTTR = avg repair time. MTBF = avg time between failures."},
  {id:"3-013",domain:"3.0",sub:"3.3",type:"single",q:"MTBF predicts:",opts:["How long repairs take","Maximum data loss","Average time between hardware failures","Recovery priority"],ans:[2],exp:"MTBF (Mean Time Between Failures) predicts the expected time between system failures."},
  {id:"3-014",domain:"3.0",sub:"3.3",type:"single",q:"Active-active redundancy means:",opts:["One device active, one standby","Both devices actively processing traffic","One device testing, one in production","Alternating between devices hourly"],ans:[1],exp:"Active-active = both devices handling traffic simultaneously. Active-passive = one active, one standby for failover."},
  {id:"3-015",domain:"3.0",sub:"3.4",type:"single",q:"DHCP DORA process order is:",opts:["Request, Offer, Discover, Acknowledge","Discover, Offer, Request, Acknowledge","Offer, Discover, Acknowledge, Request","Discover, Request, Offer, Acknowledge"],ans:[1],exp:"DORA: Discover → Offer → Request → Acknowledge."},
  {id:"3-016",domain:"3.0",sub:"3.4",type:"single",q:"DHCP T1 renewal timer is what percentage of the lease?",opts:["25%","50%","75%","87.5%"],ans:[1],exp:"T1 = 50% of lease (renewal attempt with original server). T2 = 87.5% (rebinding with any DHCP server)."},
  {id:"3-017",domain:"3.0",sub:"3.4",type:"single",q:"AAAA DNS records map hostnames to:",opts:["IPv4 addresses","IPv6 addresses","Mail servers","Canonical names"],ans:[1],exp:"AAAA = IPv6. A = IPv4. MX = mail servers. CNAME = aliases."},
  {id:"3-018",domain:"3.0",sub:"3.4",type:"single",q:"MX records specify:",opts:["IP addresses","Mail servers for a domain","Name server authority","Reverse DNS mapping"],ans:[1],exp:"MX (Mail Exchanger) records identify mail servers responsible for receiving email for a domain."},
  {id:"3-019",domain:"3.0",sub:"3.4",type:"single",q:"PTR records are used for:",opts:["Forward DNS lookups","Reverse DNS lookups (IP to name)","Email authentication","DNSSEC validation"],ans:[1],exp:"PTR records map IP addresses to hostnames (reverse lookup)—the opposite of A/AAAA records."},
  {id:"3-020",domain:"3.0",sub:"3.4",type:"single",q:"SPF and DKIM records are stored as which DNS record type?",opts:["A","MX","TXT","NS"],ans:[2],exp:"SPF and DKIM use TXT records to store email authentication information that helps prevent spoofing."},
  {id:"3-021",domain:"3.0",sub:"3.4",type:"single",q:"DNS over HTTPS (DoH) sends DNS queries over which port?",opts:["UDP 53","TCP 853","TCP 443","TCP 8443"],ans:[2],exp:"DoH sends DNS inside HTTPS traffic on port 443, making it look like normal web traffic. DoT uses port 853."},
  {id:"3-022",domain:"3.0",sub:"3.4",type:"single",q:"SLAAC allows IPv6 hosts to auto-configure addresses without:",opts:["A router","A DHCP server","A switch","An IP address"],ans:[1],exp:"SLAAC (Stateless Address Autoconfiguration) uses Router Advertisements to configure IPv6 addresses without DHCP."},
  {id:"3-023",domain:"3.0",sub:"3.5",type:"single",q:"A full tunnel VPN sends:",opts:["Only corporate traffic through the VPN","All traffic through the VPN","No traffic through the VPN","Only DNS through the VPN"],ans:[1],exp:"Full tunnel = all traffic through VPN. Split tunnel = only corporate traffic through VPN, rest goes direct."},
  {id:"3-024",domain:"3.0",sub:"3.5",type:"single",q:"RDP uses port:",opts:["22","80","443","3389"],ans:[3],exp:"RDP = TCP 3389. SSH = 22. HTTP = 80. HTTPS = 443."},
  {id:"3-025",domain:"3.0",sub:"3.5",type:"single",q:"A jump server provides:",opts:["Load balancing","Secure gateway to internal resources","DNS caching","DHCP services"],ans:[1],exp:"A jump server/box is a hardened intermediary—you connect to it first, then access internal resources from there."},
  {id:"3-026",domain:"3.0",sub:"3.5",type:"single",q:"Out-of-band management works when:",opts:["The network is fully operational","The production network is down","VPN is connected","SNMP is configured"],ans:[1],exp:"Out-of-band uses serial console/USB/modem—independent of the production network. In-band requires network connectivity."},
  {id:"3-027",domain:"3.0",sub:"3.4",type:"single",q:"NTP (Network Time Security) authenticates time using:",opts:["Community strings","TLS handshake for key exchange","MAC addresses","SNMP traps"],ans:[1],exp:"NTS uses a TLS handshake to establish trust and exchange authorization cookies for authenticated NTP communication."},
  {id:"3-028",domain:"3.0",sub:"3.4",type:"single",q:"DNSSEC provides what for DNS responses?",opts:["Encryption","Digital signatures to verify authenticity","Load balancing","Caching"],ans:[1],exp:"DNSSEC digitally signs DNS responses so clients can verify they haven't been tampered with. It does NOT encrypt."},
  {id:"3-029",domain:"3.0",sub:"3.1",type:"single",q:"IPAM (IP Address Management) helps with:",opts:["Wireless configuration","Planning, tracking, and managing IP addresses and DHCP","Firewall rule management","Routing protocol selection"],ans:[1],exp:"IPAM provides centralized management of IP addressing—DHCP scopes, reservations, usage reporting, and conflict detection."},

  // ═══════════════════════════════════════════════════════════════════════════
  // DOMAIN 4.0: NETWORK SECURITY (14% of exam) — ~45 questions
  // ═══════════════════════════════════════════════════════════════════════════

  {id:"4-001",domain:"4.0",sub:"4.1",type:"single",q:"Least privilege means:",opts:["Users get maximum permissions","Users get minimum permissions needed for their job","All users share one account","Permissions are never changed"],ans:[1],exp:"Least privilege restricts users to only the permissions required for their specific job functions."},
  {id:"4-002",domain:"4.0",sub:"4.1",type:"single",q:"The CIA triad stands for:",opts:["Compliance, Integrity, Authentication","Confidentiality, Integrity, Availability","Confidentiality, Identity, Authorization","Classification, Integrity, Accountability"],ans:[1],exp:"CIA = Confidentiality (no unauthorized access), Integrity (data unmodified), Availability (systems accessible)."},
  {id:"4-003",domain:"4.0",sub:"4.1",type:"multi",q:"Valid multifactor authentication categories include: (Choose THREE)",opts:["Something you know","Something you have","Something you are","Something you want"],ans:[0,1,2],exp:"Know (password/PIN), Have (token/card/phone), Are (biometrics). 'Somewhere you are' is sometimes a 4th factor."},
  {id:"4-004",domain:"4.0",sub:"4.1",type:"single",q:"RADIUS provides centralized:",opts:["DNS resolution","AAA (Authentication, Authorization, Accounting)","Routing","File sharing"],ans:[1],exp:"RADIUS provides centralized AAA services for network device authentication, VPN access, and 802.1X."},
  {id:"4-005",domain:"4.0",sub:"4.1",type:"single",q:"RBAC assigns permissions based on:",opts:["Individual user preferences","Organizational job roles","Time of day only","IP address"],ans:[1],exp:"RBAC (Role-Based Access Control) assigns permissions by role—manager, technician, etc."},
  {id:"4-006",domain:"4.0",sub:"4.1",type:"single",q:"TACACS+ differs from RADIUS in that it:",opts:["Uses UDP instead of TCP","Separates authentication, authorization, and accounting","Only works with Cisco devices","Has no encryption"],ans:[1],exp:"TACACS+ uses TCP and separates AAA functions (RADIUS combines auth and authorization). Both work with multiple vendors."},
  {id:"4-007",domain:"4.0",sub:"4.1",type:"single",q:"SSO (Single Sign-On) allows users to:",opts:["Use one set of credentials for multiple applications","Sign in to only one application","Change passwords automatically","Bypass MFA requirements"],ans:[0],exp:"SSO lets users authenticate once and access multiple applications without re-entering credentials."},
  {id:"4-008",domain:"4.0",sub:"4.1",type:"single",q:"SAML is used for:",opts:["File encryption","Authentication and authorization between parties","Routing protocols","VLAN configuration"],ans:[1],exp:"SAML (Security Assertion Markup Language) enables SSO by exchanging authentication data between identity providers and services."},
  {id:"4-009",domain:"4.0",sub:"4.1",type:"single",q:"A honeypot is designed to:",opts:["Encrypt sensitive data","Attract and trap attackers for analysis","Block DDoS attacks","Distribute network load"],ans:[1],exp:"Honeypots are decoy systems that attract attackers, allowing security teams to study attack methods."},
  {id:"4-010",domain:"4.0",sub:"4.2",type:"single",q:"MAC flooding attacks cause a switch to:",opts:["Encrypt all traffic","Flood traffic to all ports like a hub","Shut down completely","Block all MAC addresses"],ans:[1],exp:"MAC flooding overflows the MAC table, forcing the switch to flood all frames out every port—enabling sniffing."},
  {id:"4-011",domain:"4.0",sub:"4.2",type:"single",q:"VLAN hopping via double tagging exploits:",opts:["Weak passwords","Native VLAN configuration","DNS vulnerabilities","Wireless encryption"],ans:[1],exp:"Double tagging sends two VLAN tags. The first switch strips the outer (native) tag, letting the inner tag reach another VLAN."},
  {id:"4-012",domain:"4.0",sub:"4.2",type:"single",q:"Phishing is delivered primarily through:",opts:["Physical access","Email/text messages","USB drives","Power lines"],ans:[1],exp:"Phishing uses deceptive emails or texts to trick users into revealing credentials or clicking malicious links."},
  {id:"4-013",domain:"4.0",sub:"4.2",type:"single",q:"Tailgating involves:",opts:["Following authorized person through secured door","Intercepting wireless traffic","Modifying DNS records","Brute forcing passwords"],ans:[0],exp:"Tailgating = physically following an authorized person through a secured entrance without proper authentication."},
  {id:"4-014",domain:"4.0",sub:"4.2",type:"single",q:"DDoS differs from DoS because it comes from:",opts:["Encrypted channels","Multiple distributed sources","Internal network only","A single powerful server"],ans:[1],exp:"DDoS uses many sources simultaneously (often botnets), making it much harder to block than single-source DoS."},
  {id:"4-015",domain:"4.0",sub:"4.2",type:"single",q:"An on-path attack (formerly man-in-the-middle) involves:",opts:["Physical cable cutting","Intercepting communications between two parties","Overloading a server","Guessing passwords"],ans:[1],exp:"On-path attackers secretly intercept and potentially alter communications between two parties."},
  {id:"4-016",domain:"4.0",sub:"4.2",type:"single",q:"ARP poisoning allows an attacker to:",opts:["Encrypt network traffic","Associate their MAC with a victim's IP address","Create VLANs","Modify firewall rules"],ans:[1],exp:"ARP poisoning sends fake ARP replies to map the attacker's MAC to a legitimate IP, redirecting traffic."},
  {id:"4-017",domain:"4.0",sub:"4.2",type:"single",q:"DNS poisoning modifies:",opts:["Routing tables","DNS records to redirect traffic to malicious sites","Switch port assignments","Wireless channels"],ans:[1],exp:"DNS poisoning corrupts DNS cache/records to redirect users to attacker-controlled servers."},
  {id:"4-018",domain:"4.0",sub:"4.2",type:"single",q:"A wireless evil twin is:",opts:["A backup access point","A rogue AP mimicking a legitimate network","A redundant controller","A mesh node"],ans:[1],exp:"An evil twin mimics a legitimate AP's SSID/settings to trick users into connecting, enabling traffic interception."},
  {id:"4-019",domain:"4.0",sub:"4.2",type:"single",q:"Ransomware is malware that:",opts:["Steals processing power","Encrypts data and demands payment","Monitors keystrokes","Displays unwanted ads"],ans:[1],exp:"Ransomware encrypts victim files and demands payment for the decryption key."},
  {id:"4-020",domain:"4.0",sub:"4.2",type:"single",q:"Shoulder surfing means:",opts:["Hacking wireless signals","Watching someone enter sensitive information","Dumpster diving","Social engineering via phone"],ans:[1],exp:"Shoulder surfing = visually observing someone entering passwords, PINs, or other sensitive information."},
  {id:"4-021",domain:"4.0",sub:"4.3",type:"single",q:"Port security limits what on a switch port?",opts:["Bandwidth","Number of allowed MAC addresses","VLAN assignments","IP addresses"],ans:[1],exp:"Port security restricts the number of MAC addresses per port. Exceeding the limit can disable the port."},
  {id:"4-022",domain:"4.0",sub:"4.3",type:"single",q:"DHCP snooping prevents:",opts:["MAC flooding","Rogue DHCP servers","ARP spoofing","DNS poisoning"],ans:[1],exp:"DHCP snooping validates DHCP messages, blocking responses from unauthorized (rogue) DHCP servers."},
  {id:"4-023",domain:"4.0",sub:"4.3",type:"single",q:"Implicit deny in a firewall means:",opts:["All traffic is allowed","Unmatched traffic is blocked","Only encrypted traffic passes","Logging is disabled"],ans:[1],exp:"Implicit deny = any traffic not matching an explicit allow rule is automatically dropped."},
  {id:"4-024",domain:"4.0",sub:"4.3",type:"single",q:"A screened subnet (DMZ) hosts:",opts:["Internal databases only","Public-facing services between internal and external networks","Only wireless APs","Backup servers"],ans:[1],exp:"DMZ sits between internal trusted network and untrusted Internet, hosting web/mail/DNS servers."},
  {id:"4-025",domain:"4.0",sub:"4.3",type:"single",q:"802.1X provides:",opts:["Wireless encryption","Network Access Control (port-based authentication)","VLAN trunking","QoS prioritization"],ans:[1],exp:"802.1X controls access at the port level—devices must authenticate before getting network access."},
  {id:"4-026",domain:"4.0",sub:"4.3",type:"single",q:"Dynamic ARP Inspection prevents:",opts:["MAC flooding","ARP spoofing/poisoning","VLAN hopping","DNS cache poisoning"],ans:[1],exp:"DAI validates ARP packets against the DHCP snooping binding table, blocking spoofed ARP messages."},
  {id:"4-027",domain:"4.0",sub:"4.3",type:"single",q:"Geofencing restricts access based on:",opts:["Time of day","Physical location","User role","Device type"],ans:[1],exp:"Geofencing automatically allows/restricts access based on whether the user is within a defined geographic area."},
  {id:"4-028",domain:"4.0",sub:"4.1",type:"single",q:"PKI (Public Key Infrastructure) manages:",opts:["IP addresses","Digital certificates and encryption keys","Physical door locks","Firewall rules"],ans:[1],exp:"PKI manages the creation, distribution, storage, and revocation of digital certificates for encryption and authentication."},
  {id:"4-029",domain:"4.0",sub:"4.1",type:"single",q:"TOTP generates one-time passwords based on:",opts:["Username only","A secret key and current time","MAC address","IP address"],ans:[1],exp:"TOTP (Time-based OTP) uses a shared secret key and the current time to generate codes that change every 30 seconds."},

  // ═══════════════════════════════════════════════════════════════════════════
  // DOMAIN 5.0: NETWORK TROUBLESHOOTING (24% of exam) — ~70 questions
  // ═══════════════════════════════════════════════════════════════════════════

  {id:"5-001",domain:"5.0",sub:"5.1",type:"single",q:"FIRST step in CompTIA troubleshooting methodology?",opts:["Establish theory","Identify the problem","Test theory","Create plan of action"],ans:[1],exp:"Step 1: Identify the problem (gather info, question users, identify symptoms, determine changes)."},
  {id:"5-002",domain:"5.0",sub:"5.1",type:"single",q:"After implementing a fix, the NEXT step is:",opts:["Document findings","Close ticket","Verify full system functionality","Establish new theory"],ans:[2],exp:"After implementing: verify functionality → implement preventive measures → THEN document findings."},
  {id:"5-003",domain:"5.0",sub:"5.1",type:"single",q:"If your initial theory doesn't work, you should:",opts:["Implement the fix anyway","Re-establish a new theory or escalate","Document and close","Restart the device"],ans:[1],exp:"If theory isn't confirmed, re-establish a new theory or escalate to a higher tier. Don't keep trying failed solutions."},
  {id:"5-004",domain:"5.0",sub:"5.1",type:"single",q:"The LAST step in the troubleshooting methodology is:",opts:["Implement the solution","Verify functionality","Document findings, actions, and outcomes","Test the theory"],ans:[2],exp:"Final step: document everything—findings, actions taken, outcomes. This builds the knowledge base."},
  {id:"5-005",domain:"5.0",sub:"5.2",type:"single",q:"Pins 1,2 mapped to 3,6 at the other end indicates what cable type?",opts:["Straight-through","Crossover","Rollover","Loopback"],ans:[1],exp:"Crossover swaps transmit/receive pairs (1,2↔3,6). Used for connecting like devices before Auto-MDIX."},
  {id:"5-006",domain:"5.0",sub:"5.2",type:"single",q:"Signal weakening over distance is called:",opts:["Crosstalk","Attenuation","Jitter","Latency"],ans:[1],exp:"Attenuation = signal strength loss over distance. Exceeding max cable length causes it."},
  {id:"5-007",domain:"5.0",sub:"5.2",type:"single",q:"Signal leaking between adjacent wire pairs is:",opts:["Attenuation","EMI","Crosstalk","Jitter"],ans:[2],exp:"Crosstalk = signal interference between wire pairs in the same cable. The twist in twisted-pair reduces this."},
  {id:"5-008",domain:"5.0",sub:"5.2",type:"single",q:"EMI is most likely caused by:",opts:["Long cable runs","Fluorescent lights and elevator machinery","Incorrect VLAN config","DHCP failure"],ans:[1],exp:"EMI (Electromagnetic Interference) comes from electrical devices—motors, fluorescent lights, power cables."},
  {id:"5-009",domain:"5.0",sub:"5.2",type:"single",q:"A duplex mismatch causes:",opts:["Complete link failure","Excessive collisions and slow performance","IP address conflicts","DNS resolution errors"],ans:[1],exp:"When one end is full-duplex and the other half-duplex, full-duplex traffic looks like collisions to the half-duplex side."},
  {id:"5-010",domain:"5.0",sub:"5.2",type:"single",q:"CRC errors on an interface are commonly caused by:",opts:["DHCP misconfiguration","EMI or damaged cables","Incorrect subnet mask","Routing loops"],ans:[1],exp:"CRC (Cyclic Redundancy Check) errors indicate frame corruption, typically from EMI, bad cables, or damaged connectors."},
  {id:"5-011",domain:"5.0",sub:"5.2",type:"single",q:"Runts are Ethernet frames smaller than:",opts:["46 bytes","64 bytes","128 bytes","1518 bytes"],ans:[1],exp:"Runts < 64 bytes (minimum Ethernet frame size). Giants > 1518 bytes. Both indicate NIC or collision issues."},
  {id:"5-012",domain:"5.0",sub:"5.3",type:"single",q:"User can access sites by IP but NOT by name. Problem is:",opts:["DHCP failure","DNS resolution failure","Default gateway issue","Firewall blocking"],ans:[1],exp:"Reaching by IP proves connectivity works. Failing by name = DNS problem (server unreachable or misconfigured)."},
  {id:"5-013",domain:"5.0",sub:"5.3",type:"single",q:"Client gets 169.254.x.x address. Check first:",opts:["DNS server","DHCP server connectivity","Default gateway","Firewall rules"],ans:[1],exp:"APIPA address = no DHCP response. Verify DHCP server is running, reachable, and has available addresses."},
  {id:"5-014",domain:"5.0",sub:"5.3",type:"single",q:"Users on VLAN 10 can't reach VLAN 20 but can reach each other. Need:",opts:["New switch","Layer 3 device (router or L3 switch)","Longer cables","DHCP server"],ans:[1],exp:"Inter-VLAN routing requires a Layer 3 device. VLANs are separate broadcast domains."},
  {id:"5-015",domain:"5.0",sub:"5.3",type:"single",q:"A routing loop causes packets to:",opts:["Arrive at the correct destination quickly","Circulate endlessly between routers","Get encrypted automatically","Be forwarded to the default gateway"],ans:[1],exp:"Routing loops cause packets to bounce between routers indefinitely. TTL eventually drops them."},
  {id:"5-016",domain:"5.0",sub:"5.3",type:"single",q:"Two devices have the same IP address. This causes:",opts:["Faster performance","Intermittent connectivity for both","Increased security","VLAN issues"],ans:[1],exp:"Duplicate IPs cause intermittent connectivity—both devices 'fight' for the address, and the OS flags the conflict."},
  {id:"5-017",domain:"5.0",sub:"5.3",type:"single",q:"A switch port in 'error disabled' state was likely triggered by:",opts:["Normal traffic","Port security violation or link flapping","DHCP request","DNS query"],ans:[1],exp:"Error disabled = switch automatically shut down the port due to security violation, link flapping, or BPDU guard."},
  {id:"5-018",domain:"5.0",sub:"5.3",type:"single",q:"DHCP scope exhaustion means:",opts:["The DHCP server crashed","No available IP addresses left in the pool","DNS is not responding","The default gateway is wrong"],ans:[1],exp:"Exhaustion = all IPs in the DHCP scope are leased. New clients can't get addresses. Solutions: expand pool, lower lease time."},
  {id:"5-019",domain:"5.0",sub:"5.4",type:"single",q:"Choppy VoIP calls are most likely caused by:",opts:["Low bandwidth","High latency","Excessive jitter","Packet loss"],ans:[2],exp:"Jitter (variation in packet arrival times) is the primary cause of choppy/garbled voice quality."},
  {id:"5-020",domain:"5.0",sub:"5.4",type:"single",q:"Network congestion occurs when:",opts:["All devices have static IPs","Traffic exceeds available bandwidth","VLANs are properly configured","Cables are too short"],ans:[1],exp:"Congestion happens when traffic demand exceeds network capacity, causing queuing, buffering, and dropped packets."},
  {id:"5-021",domain:"5.0",sub:"5.4",type:"single",q:"Replacing a hub with a switch improves performance because:",opts:["Switches are faster processors","Each port gets its own collision domain","Switches encrypt traffic","Switches use fiber only"],ans:[1],exp:"Switches create dedicated collision domains per port, eliminating collisions. Hubs share one collision domain."},
  {id:"5-022",domain:"5.0",sub:"5.4",type:"single",q:"Throughput differs from bandwidth because:",opts:["They are the same thing","Throughput is theoretical, bandwidth is actual","Throughput is actual data transferred, bandwidth is theoretical max","Throughput only applies to wireless"],ans:[2],exp:"Bandwidth = theoretical maximum capacity. Throughput = actual data successfully transferred in practice."},
  {id:"5-023",domain:"5.0",sub:"5.5",type:"single",q:"'ping' tests connectivity using which protocol?",opts:["TCP","UDP","ICMP","ARP"],ans:[2],exp:"Ping sends ICMP Echo Requests and listens for Echo Replies to test connectivity and measure round-trip time."},
  {id:"5-024",domain:"5.0",sub:"5.5",type:"single",q:"'traceroute' shows each router hop using:",opts:["ARP requests","Incrementing TTL values","DNS queries","SNMP polls"],ans:[1],exp:"Traceroute sends packets with increasing TTL values. Each router decrements TTL and returns ICMP Time Exceeded when it hits 0."},
  {id:"5-025",domain:"5.0",sub:"5.5",type:"single",q:"'arp -a' displays:",opts:["Active TCP connections","IP-to-MAC address mappings","DNS cache entries","Routing table"],ans:[1],exp:"'arp -a' shows the local ARP cache—recently resolved IP-to-MAC address mappings."},
  {id:"5-026",domain:"5.0",sub:"5.5",type:"single",q:"'ipconfig /release' does what on Windows?",opts:["Renews the DHCP lease","Releases the current DHCP lease","Flushes DNS cache","Shows all IP configuration"],ans:[1],exp:"/release drops the current DHCP lease. /renew requests a new one. /flushdns clears DNS cache. /all shows full config."},
  {id:"5-027",domain:"5.0",sub:"5.5",type:"single",q:"'ipconfig /flushdns' clears:",opts:["ARP cache","DHCP lease","DNS resolver cache","Routing table"],ans:[2],exp:"Flushing DNS clears cached name resolutions, forcing fresh DNS lookups. Useful when DNS records have changed."},
  {id:"5-028",domain:"5.0",sub:"5.5",type:"single",q:"'nslookup' is used to:",opts:["Test connectivity","Query DNS servers for name resolution","View MAC addresses","Display routing table"],ans:[1],exp:"nslookup queries DNS servers to resolve hostnames to IPs (and vice versa) for DNS troubleshooting."},
  {id:"5-029",domain:"5.0",sub:"5.5",type:"single",q:"'netstat -a' shows:",opts:["All active network connections and listening ports","ARP table","DNS cache","Routing table"],ans:[0],exp:"netstat -a displays all active connections and listening ports. -b shows binaries, -n skips name resolution."},
  {id:"5-030",domain:"5.0",sub:"5.5",type:"single",q:"Wireshark/tcpdump are examples of:",opts:["Vulnerability scanners","Protocol analyzers","Port scanners","Wireless analyzers"],ans:[1],exp:"Protocol analyzers capture and analyze packets at the frame level for detailed traffic inspection."},
  {id:"5-031",domain:"5.0",sub:"5.5",type:"single",q:"A tone and probe kit traces:",opts:["IP addresses","Physical cable runs through walls","Wireless signals","Network utilization"],ans:[1],exp:"Tone generator sends audible signal; inductive probe locates the wire without touching copper. 'Fox and hound.'"},
  {id:"5-032",domain:"5.0",sub:"5.5",type:"single",q:"A visual fault locator finds fiber issues by:",opts:["Measuring resistance","Shining visible light that escapes at breaks","Sending ICMP packets","Testing signal strength wirelessly"],ans:[1],exp:"VFL shines red laser through fiber. Light leaks at breaks, tight bends, or bad splices—visible through the jacket."},
  {id:"5-033",domain:"5.0",sub:"5.5",type:"single",q:"'show mac-address-table' on a switch displays:",opts:["Routing information","MAC addresses associated with each port","VLAN configuration","Interface error counts"],ans:[1],exp:"This command shows which MAC addresses the switch has learned on each port—essential for troubleshooting connectivity."},
  {id:"5-034",domain:"5.0",sub:"5.5",type:"single",q:"'show route' on a router displays:",opts:["MAC address table","Current routing table with known routes","VLAN database","Interface statistics"],ans:[1],exp:"'show route' (or 'show ip route') displays all routes, next hops, metrics, and administrative distances."},
  {id:"5-035",domain:"5.0",sub:"5.5",type:"single",q:"'show interface' displays:",opts:["Only IP addresses","Status, speed, duplex, MTU, error counts","VLAN assignments only","Routing protocols only"],ans:[1],exp:"'show interface' provides comprehensive port info: up/down status, speed, duplex, MTU, CRC errors, drops, etc."},
  {id:"5-036",domain:"5.0",sub:"5.5",type:"single",q:"'show vlan' displays:",opts:["Routing table","VLANs and associated switch interfaces","MAC address table","Interface errors"],ans:[1],exp:"'show vlan' shows all configured VLANs and which switch ports are assigned to each—key for VLAN troubleshooting."},
  {id:"5-037",domain:"5.0",sub:"5.5",type:"single",q:"'ifconfig' and 'ip address' are used on which operating system?",opts:["Windows","Linux/macOS","Cisco IOS","SNMP"],ans:[1],exp:"'ifconfig' (legacy) and 'ip address' (modern) display/manage network interface configuration on Linux/macOS."},
  {id:"5-038",domain:"5.0",sub:"5.5",type:"single",q:"Nmap is primarily used for:",opts:["Cable testing","Network scanning and port discovery","DNS resolution","Traffic shaping"],ans:[1],exp:"Nmap scans networks to find devices, open ports, running services, and OS versions—essential for security auditing."},
  {id:"5-039",domain:"5.0",sub:"5.2",type:"single",q:"An optical link budget calculation determines:",opts:["Cable category requirements","Whether fiber signal loss is acceptable for the link","Maximum VLAN count","Switch port speed"],ans:[1],exp:"Optical link budget adds up all loss factors (distance, connectors, splices) to verify the signal reaches the receiver."},
  {id:"5-040",domain:"5.0",sub:"5.4",type:"single",q:"Latency is best described as:",opts:["Amount of data per second","Delay between request and response","Variation in packet arrival times","Number of dropped packets"],ans:[1],exp:"Latency = delay/waiting time. Throughput = data volume. Jitter = variation in delay. Packet loss = dropped data."},
];

export default QUESTIONS;
